import React from 'react';
import styled, { keyframes } from 'styled-components';
import { useTranslation } from 'react-i18next';

const slideAnimation = keyframes`
  0% { top: -100%; }
  100% { top: 100%; }
`;

const LoaderContainer = styled.div`
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100vh;
`;

const Loader = styled.div`
  background: transparent;
  position: relative;
  height: 75px;
  width: 100px;
  overflow: hidden;
  box-shadow: -1px 12px 14px -15px #0000002b;

  &:after {
    content: '';
    width: 100%;
    height: 57.75px;
    position: absolute;
    top: 0;
    left: 0;
    background: linear-gradient(180deg, rgb(242, 242, 242) 0%, rgba(242,242,242,0) 100%);
  }
`;

const Note = styled.div`
  position: absolute;
  background: linear-gradient(180deg, #F16E76 0%, #E6548A 100%);
  width: 14px;
  height: 75px;
  top: 100%;
  border-radius: 12px;
`;

const Note0 = styled(Note)`
  left: 32px;
  animation: ${slideAnimation} 2s infinite ease-out;
`;

const Note1 = styled(Note)`
  left: 49px;
  animation: ${slideAnimation} 2s infinite 0.35s ease-out;
`;

const Note2 = styled(Note)`
  left: 66px;
  animation: ${slideAnimation} 2s infinite 0.7s ease-out;
`;

const Note3 = styled(Note)`
  left: 83px;
  animation: ${slideAnimation} 2s infinite 1.05s ease-out;
`;

const Note4 = styled(Note)`
  left: 100px;
  animation: ${slideAnimation} 2s infinite 1.4s ease-out;
`;

const StatusText = styled.div`
  color: #70757D;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, 'Noto Sans', sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol', 'Noto Color Emoji';
  margin-top: 1rem;
`;

const MusicLoader = () => {
  const { t } = useTranslation();

  return (
    <LoaderContainer>
      <Loader>
        <Note0 />
        <Note1 />
        <Note2 />
        <Note3 />
        <Note4 />
      </Loader>
      <StatusText>{t('loading')}</StatusText>
    </LoaderContainer>
  );
};

export default MusicLoader;
